describe('Game Engine server', () => {
  const instance = startServer(0); // random port

  afterAll(() => new Promise<void>(resolve => instance.server.close(() => resolve())));

  it('GET /health returns 200', async () => {
    await instance.ready;
    const res = await fetch(`http://localhost:${instance.port}/health`);
    expect(res.status).toBe(200);
    const body = await res.json() as Record<string, unknown>;
    expect(body.status).toBe('ok');
    expect(body.service).toBe('Game Engine');
  });

  it('GET /metrics returns request counts', async () => {
    await instance.ready;
    const res = await fetch(`http://localhost:${instance.port}/metrics`);
    expect(res.status).toBe(200);
    const body = await res.json() as Record<string, unknown>;
    expect(typeof body.requests_total).toBe('number');
  });

  it('GET /modules lists all registered modules', async () => {
    await instance.ready;
    const res = await fetch(`http://localhost:${instance.port}/modules`);
    expect(res.status).toBe(200);
    const body = await res.json() as Array<Record<string, unknown>>;
    expect(body.length).toBe(4);
  });

  it('GET /unknown returns 404', async () => {
    await instance.ready;
    const res = await fetch(`http://localhost:${instance.port}/unknown`);
    expect(res.status).toBe(404);
  });
});
